import{_ as t,o,c as n,ag as a}from"./chunks/framework.CMWvBNEy.js";const i="/mocking-gui/mocking-gui-architecture.png",p=JSON.parse('{"title":"Introduction to Mocking GUI","description":"","frontmatter":{"sidebar_position":1},"headers":[],"relativePath":"guide/introduction.md","filePath":"guide/introduction.md"}'),r={name:"guide/introduction.md"};function s(c,e,l,d,g,u){return o(),n("div",null,[...e[0]||(e[0]=[a('<h1 id="introduction-to-mocking-gui" tabindex="-1">Introduction to Mocking GUI <a class="header-anchor" href="#introduction-to-mocking-gui" aria-label="Permalink to &quot;Introduction to Mocking GUI&quot;">​</a></h1><p><strong>Mocking GUI</strong> is a <strong>GUI tool optimized for HTTP-based API mocking</strong>.</p><p><img src="'+i+'" alt="Mocking GUI Architecture"></p><p>The library is built on MSW 2.x&#39;s <code>http</code> namespace and supports mocking for the following types of HTTP requests/responses:</p><ul><li>HTTP requests generated by <code>fetch</code>, <code>XMLHttpRequest</code>, etc.</li><li>HTTP methods such as <code>GET</code>, <code>POST</code>, <code>PUT</code>, <code>PATCH</code>, <code>DELETE</code>, etc.</li></ul><p>Through its control panel, you can manipulate API responses in real-time and easily verify various test scenarios without changing code.</p><h2 id="why-mocking-gui" tabindex="-1">Why Mocking GUI? <a class="header-anchor" href="#why-mocking-gui" aria-label="Permalink to &quot;Why Mocking GUI?&quot;">​</a></h2><p>MSW is an excellent library, but managing handlers purely through code can be cumbersome. To make a specific API return an error or add delay, you often have to modify code and refresh the page.</p><p>Mocking GUI solves these problems:</p><ul><li><strong>GUI-First</strong>: Change API states (Success/Error/Loading) instantly from the panel with a single click, without code changes.</li><li><strong>Enhanced Collaboration</strong>: Save complex bug reproduction steps as &quot;Scenarios&quot; and share them with your team.</li><li><strong>Easy Setup</strong>: Provides an instant mocking environment with minimal configuration and supports mock state synchronization between browser and server.</li></ul><h2 id="key-features" tabindex="-1">Key Features <a class="header-anchor" href="#key-features" aria-label="Permalink to &quot;Key Features&quot;">​</a></h2><ul><li><strong>Powerful Control Panel</strong>: Control handler activation, mode (Auto/Manual/Swagger), response variants, and delays instantly from the GUI.</li><li><strong>Server Synchronization</strong>: Cookie-based state synchronization ensures consistent mocking behavior across CSR, Next.js (SSR/RSC), Remix, and other server-side rendering environments.</li><li><strong>Swagger/OpenAPI Automation</strong>: Load Swagger documents to instantly create a mock server and control responses without writing code.</li><li><strong>Scenario Management</strong>: Save complex API state combinations (e.g., No User + Payment Failed) as a single &quot;Scenario&quot; to restore and share with one click.</li><li><strong>Style Isolation</strong>: Uses Shadow DOM to provide a safe overlay without conflicting with your application&#39;s CSS.</li></ul><h2 id="getting-started" tabindex="-1">Getting Started <a class="header-anchor" href="#getting-started" aria-label="Permalink to &quot;Getting Started&quot;">​</a></h2><p>Ready to introduce Mocking GUI to your project?</p><p>👉 <strong><a href="./quick-start.html">Installation &amp; Setup Guide</a></strong> - Get started in 3 minutes with detailed installation instructions and framework integration examples.</p><p>For advanced usage:</p><ul><li><strong><a href="./usage/swagger-guide.html">Swagger Automation</a></strong> - Connect your existing API docs for instant mock generation</li><li><strong><a href="./usage/api-guide.html">Usage Guides</a></strong> - Learn about handlers, scenarios, and advanced features</li></ul>',17)])])}const m=t(r,[["render",s]]);export{p as __pageData,m as default};
